create index 게시판_idx on 게시판(작성일시, 게시판구분);

select *
from (
  select *
  from 게시판
  where 게시판구분 = :gubun
  and 작성일시 >= trunc(sysdate) - 1
  order by 작성일시, 작성자명
)
where rownum <= 100;

