create table 거래(
  계좌번호 number,
  상품번호 varchar2(6),
  거래일자 varchar2(8),
  거래량 number,
  거래금액 number
)
partition by range(거래일자) (
  partition p1 values less than('20110101'),
  partition p2 values less than('20120101'),
  partition px values less than(maxvalue)
);

create index 거래_idx2 on 거래(계좌번호, 거래일자) LOCAL;
